import express from 'express';
import path from 'path';

const app = express();

const publicDir = path.join(__dirname, '..', 'public');

app.use(express.static(publicDir));

app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });
});

app.get('/', (_req, res) => {
  res.sendFile(path.join(publicDir, 'index.html'));
});

const PORT = Number(process.env.PORT) || 3000;

if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server listening on http://localhost:${PORT}`);
  });
}

export default app;

import { strict as assert } from 'assert';
import { readFileSync } from 'fs';
import path from 'path';

describe('Project dependencies', () => {
  const pkgPath = path.join(__dirname, '..', 'package.json');
  const pkg = JSON.parse(readFileSync(pkgPath, 'utf-8')) as {
    dependencies?: Record<string, string>;
    devDependencies?: Record<string, string>;
  };

  function hasDep(name: string): boolean {
    return Boolean((pkg.dependencies && pkg.dependencies[name]) || (pkg.devDependencies && pkg.devDependencies[name]));
  }

  ['express', 'tailwindcss', 'postcss', 'autoprefixer'].forEach((dep) => {
    it(`includes ${dep} in dependencies or devDependencies`, () => {
      assert.ok(hasDep(dep), `Expected ${dep} to be listed in package.json`);
    });
  });
});
